&lt;!-- KPFK ABOUT PAGE — AIIR CMS BLOCKS — v3 --&gt;
&lt;!-- Updated: Feb 2026 --&gt;


&lt;!-- ==================== BLOCK 1: HERO ==================== --&gt;
&lt;div id=&quot;hero&quot; style=&quot;background:#1a1a1a; color:#fff; padding:3rem 1.5rem; font-family:Georgia,&#039;Times New Roman&#039;,serif;&quot;&gt;
  &lt;div style=&quot;max-width:800px; margin:0 auto;&quot;&gt;
    &lt;img alt=&quot;KPFK Transmitter&quot; src=&quot;https://mmo.aiircdn.com/237/685a4388b63fd.png&quot; style=&quot;max-width:100%; height:auto; margin-bottom:1.5rem; display:block;&quot; /&gt;
    &lt;div style=&quot;font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:900; font-size:2.4rem; text-transform:uppercase; letter-spacing:-0.02em; margin-bottom:0.25rem; line-height:1.1;&quot;&gt;KPFK 90.7 FM&lt;/div&gt;
    &lt;div style=&quot;font-family:&#039;Courier New&#039;,monospace; font-size:12px; font-weight:700; text-transform:uppercase; letter-spacing:0.5px; color:#c41e3a; margin-bottom:1.5rem;&quot;&gt;LISTENER-POWERED SINCE 1959&lt;/div&gt;
    &lt;div style=&quot;border-top:4px solid #c41e3a; padding-top:1.5rem; margin-bottom:1.5rem;&quot;&gt;
      &lt;p style=&quot;font-size:1.1rem; line-height:1.7; color:#ddd; margin:0 0 1rem 0;&quot;&gt;KPFK is a listener-powered radio station in Los Angeles. We broadcast the stuff that gets left out: the stories corporate media won&#039;t run, the music commercial stations won&#039;t play, the conversations that don&#039;t fit into a four-minute segment.&lt;/p&gt;
      &lt;p style=&quot;font-size:1.1rem; line-height:1.7; color:#ddd; margin:0 0 1rem 0;&quot;&gt;No ads. No sponsors. No billionaire backers. We&#039;ve operated that way since 1959, funded entirely by the people who listen.&lt;/p&gt;
      &lt;p style=&quot;font-size:1.1rem; line-height:1.7; color:#ddd; margin:0;&quot;&gt;Media consolidation is accelerating. Local news is disappearing. KPFK is still here because our listeners keep us here.&lt;/p&gt;
    &lt;/div&gt;
    &lt;div style=&quot;display:flex; flex-wrap:wrap; gap:12px;&quot;&gt;
      &lt;a href=&quot;/donate&quot; style=&quot;display:inline-block; background:#c41e3a; color:#fff; font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:700; font-size:14px; text-transform:uppercase; letter-spacing:0.5px; padding:14px 28px; text-decoration:none; border:3px solid #c41e3a;&quot;&gt;SUPPORT THE SIGNAL&lt;/a&gt;
      &lt;a href=&quot;/listen&quot; style=&quot;display:inline-block; background:transparent; color:#fff; font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:700; font-size:14px; text-transform:uppercase; letter-spacing:0.5px; padding:14px 28px; text-decoration:none; border:3px solid #fff;&quot;&gt;LISTEN LIVE&lt;/a&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;


&lt;!-- ==================== BLOCK 2: WHERE WE COME FROM ==================== --&gt;
&lt;div id=&quot;history&quot; style=&quot;background:#fff; color:#1a1a1a; padding:3rem 1.5rem; font-family:Georgia,&#039;Times New Roman&#039;,serif; border-bottom:3px solid #e0e0e0;&quot;&gt;
  &lt;div style=&quot;max-width:900px; margin:0 auto; display:flex; flex-wrap:wrap; gap:2rem; align-items:flex-start;&quot;&gt;
    &lt;div style=&quot;flex:1 1 480px; min-width:280px;&quot;&gt;
      &lt;div style=&quot;font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:900; font-size:1.8rem; text-transform:uppercase; letter-spacing:-0.02em; margin-bottom:1.25rem; line-height:1.1;&quot;&gt;Where We Come From&lt;/div&gt;
      &lt;p style=&quot;font-size:1.05rem; line-height:1.7; margin:0 0 1rem 0;&quot;&gt;KPFK was started in 1959 by the Pacifica Foundation, an organization built by WWII-era pacifists who wanted a media platform that didn&#039;t answer to the government or advertisers. That idea was considered radical then. It still is.&lt;/p&gt;
      &lt;p style=&quot;font-size:1.05rem; line-height:1.7; margin:0 0 1rem 0;&quot;&gt;We were the first full-time FM station west of the Mississippi powered entirely by listener donations. From the beginning, the mission was plain: serve peace, culture, and honest public conversation without compromise.&lt;/p&gt;
      &lt;p style=&quot;font-size:1.05rem; line-height:1.7; margin:0 0 1rem 0;&quot;&gt;The station has survived FBI surveillance, FCC investigations, governance crises, financial hardship, and more internal fights than anyone wants to count. We&#039;re still broadcasting because our listeners refused to let us go dark.&lt;/p&gt;
      &lt;p style=&quot;font-size:1.05rem; line-height:1.7; margin:0;&quot;&gt;Our structure is unusual: a locally elected station board and a national nonprofit ensure we answer to people, not shareholders. KPFK is one of the last media institutions in America where the public actually holds the mic.&lt;/p&gt;
    &lt;/div&gt;
    &lt;div style=&quot;flex:1 1 360px; min-width:280px;&quot;&gt;
      &lt;img alt=&quot;Historic photo of KPFK studio&quot; src=&quot;https://mmo.aiircdn.com/237/685a4e617e848.jpeg&quot; style=&quot;width:100%; height:auto; border:3px solid #1a1a1a; display:block; filter:grayscale(30%);&quot; /&gt;
      &lt;div style=&quot;font-family:&#039;Courier New&#039;,monospace; font-size:10px; font-weight:700; text-transform:uppercase; letter-spacing:0.5px; color:#999; margin-top:8px;&quot;&gt;KPFK Archives&lt;/div&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;


&lt;!-- ==================== BLOCK 3: TIMELINE ==================== --&gt;
&lt;div id=&quot;timeline&quot; style=&quot;background:#f8f8f8; color:#1a1a1a; padding:3rem 1.5rem; font-family:Georgia,&#039;Times New Roman&#039;,serif; border-bottom:3px solid #e0e0e0;&quot;&gt;
  &lt;div style=&quot;max-width:800px; margin:0 auto;&quot;&gt;
    &lt;div style=&quot;font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:900; font-size:1.8rem; text-transform:uppercase; letter-spacing:-0.02em; margin-bottom:2rem; line-height:1.1;&quot;&gt;On the Record&lt;/div&gt;

    &lt;style&gt;
      .kpfk-tl details {
        border: 3px solid #1a1a1a;
        margin-bottom: -3px;
      }
      .kpfk-tl details:last-child {
        margin-bottom: 0;
      }
      .kpfk-tl summary {
        display: flex;
        align-items: baseline;
        gap: 12px;
        padding: 16px;
        cursor: pointer;
        list-style: none;
        background: #fff;
        transition: background 0.15s, color 0.15s;
        user-select: none;
      }
      .kpfk-tl summary::-webkit-details-marker { display: none; }
      .kpfk-tl summary::marker { display: none; content: &#039;&#039;; }
      .kpfk-tl summary:hover { background: #f0f0f0; }
      .kpfk-tl details[open] &gt; summary {
        border-bottom: 3px solid #c41e3a;
        background: #1a1a1a;
        color: #fff;
      }
      .kpfk-tl details[open] &gt; summary:hover { background: #1a1a1a; }
      .kpfk-tl details[open] &gt; summary .tl-teaser { color: #999; }
      .kpfk-tl details[open] &gt; summary .tl-decade { color: #c41e3a; }
      .kpfk-tl details[open] &gt; summary .tl-arrow { transform: rotate(90deg); }
      .kpfk-tl .tl-arrow {
        font-size: 14px;
        font-weight: 700;
        color: #c41e3a;
        flex-shrink: 0;
        transition: transform 0.15s;
        width: 12px;
        text-align: center;
        font-family: &#039;Courier New&#039;, monospace;
      }
      .kpfk-tl .tl-decade {
        font-family: &#039;Courier New&#039;, monospace;
        font-size: 13px;
        font-weight: 700;
        color: #c41e3a;
        min-width: 70px;
        flex-shrink: 0;
      }
      .kpfk-tl .tl-teaser {
        font-family: Georgia, &#039;Times New Roman&#039;, serif;
        font-size: 0.95rem;
        color: #555;
        font-style: italic;
      }
      .kpfk-tl .tl-entry {
        display: flex;
        gap: 16px;
        padding: 12px 16px 12px 42px;
        border-bottom: 1px solid #e0e0e0;
        align-items: baseline;
        background: #fff;
      }
      .kpfk-tl .tl-entry:last-child { border-bottom: none; }
      .kpfk-tl .tl-entry:nth-child(even) { background: #fafafa; }
      .kpfk-tl .tl-year {
        font-family: &#039;Courier New&#039;, monospace;
        font-size: 11px;
        font-weight: 700;
        color: #c41e3a;
        min-width: 36px;
        flex-shrink: 0;
      }
      .kpfk-tl .tl-content div:first-child {
        font-family: &#039;Helvetica Neue&#039;, Helvetica, Arial, sans-serif;
        font-size: 0.85rem;
        font-weight: 900;
        text-transform: uppercase;
        letter-spacing: -0.01em;
        color: #1a1a1a;
      }
      .kpfk-tl .tl-content p {
        font-size: 0.85rem;
        line-height: 1.5;
        margin: 3px 0 0 0;
        color: #444;
      }
      .o-headline { display: none !important; }
      .kpfk-email {
        unicode-bidi: bidi-override;
        direction: rtl;
        font-family: &#039;Courier New&#039;, monospace;
        font-size: 11px;
        font-weight: 700;
        letter-spacing: 0.3px;
        color: #888;
        text-decoration: none;
        flex-basis: 100%;
        margin-top: 2px;
      }
      .kpfk-email:hover { color: #c41e3a; }
      @media (max-width: 480px) {
        .kpfk-tl .tl-entry { padding-left: 16px; }
        .kpfk-tl .tl-decade { min-width: 58px; font-size: 12px; }
        .kpfk-tl .tl-teaser { font-size: 0.85rem; }
      }
    &lt;/style&gt;

    &lt;div class=&quot;kpfk-tl&quot;&gt;

      &lt;!-- 1940s-50s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;1940s–50s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Pacifica is born. KPFK hits the airwaves.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1949&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Pacifica Radio Is Born&lt;/div&gt;
            &lt;p&gt;Pacifica launches KPFA in Berkeley. First listener-sponsored, non-commercial station in the country. Built by conscientious objectors who believed radio could be something other than a sales pitch.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1959&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;KPFK Goes on the Air&lt;/div&gt;
            &lt;p&gt;Pacifica&#039;s second station launches from Mt. Wilson at 110,000 watts. One of the most powerful FM signals in the western U.S. Terry Drinkwater is the first general manager.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 1960s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;1960s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Peabody Award. FCC investigation. The first Ren Faire.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1961&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Peabody Award&lt;/div&gt;
            &lt;p&gt;Two years in and KPFK wins Pacifica&#039;s second George Foster Peabody Award for journalism that challenged Cold War groupthink.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1962&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;FCC Investigates&lt;/div&gt;
            &lt;p&gt;The FCC withholds license renewals for Pacifica stations, investigating supposed &amp;ldquo;communist affiliations.&amp;rdquo; Pacifica was never cited. The FCC chair later criticized the broadcast industry for not defending them.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1963&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;The First Renaissance Faire&lt;/div&gt;
            &lt;p&gt;KPFK organizes the original Renaissance Pleasure Faire as a fundraiser. It becomes a cultural institution that outlives its radio origins by decades.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 1970s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;1970s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Jailed for journalism. IMRU goes on the air.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1974&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Jailed for Journalism&lt;/div&gt;
            &lt;p&gt;The Symbionese Liberation Army delivers the Patty Hearst tapes to KPFK. General Manager Will Lewis spends 15 days in jail for refusing to hand them over to the FBI.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1974&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;IMRU Launches&lt;/div&gt;
            &lt;p&gt;One of the first LGBTQ+ radio programs in the U.S. goes on air at KPFK. Still running. Longest-running queer radio show in American history.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 1980s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;1980s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Censorship fights. Ladysmith Black Mambazo.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1986&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;FCC vs. &lt;em style=&quot;text-transform:none&quot;&gt;Jerker&lt;/em&gt;&lt;/div&gt;
            &lt;p&gt;KPFK airs Robert Chesley&#039;s AIDS-era play. The FCC rewrites its indecency rules in response, using the broadcast as its test case.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1987&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Ladysmith Black Mambazo&lt;/div&gt;
            &lt;p&gt;Fresh off Paul Simon&#039;s &lt;em&gt;Graceland&lt;/em&gt;, the group makes their first live U.S. radio appearance on KPFK.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 1990s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;1990s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Democracy Now! The governance crisis.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1992&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Republicans Target Pacifica&lt;/div&gt;
            &lt;p&gt;Senate Republicans impose &amp;ldquo;objectivity and balance&amp;rdquo; conditions on public broadcasting funding. A CPB board member files a complaint against KPFK specifically, citing its Black History Month programming.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1996&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Democracy Now! Launches&lt;/div&gt;
            &lt;p&gt;Amy Goodman and Juan Gonz&amp;aacute;lez debut the show on the Pacifica network. It becomes the most recognized program in independent media, now carried by over 700 stations.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;1999&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;The Governance Crisis&lt;/div&gt;
            &lt;p&gt;Pacifica&#039;s national board tries to centralize programming and chase corporate-style funding. Staff walk out across all five stations. Court battles and protests follow. Listeners fight to keep the network independent, permanently reshaping Pacifica&#039;s bylaws.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 2000s --&gt;
      &lt;details&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;2000s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;Spanish-language news comes to KPFK.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;2006&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Informativo Pacifica&lt;/div&gt;
            &lt;p&gt;KPFK launches a daily Spanish-language newscast with reporters across the U.S. and Latin America. One of the few independent Spanish-language news programs on American radio.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

      &lt;!-- 2020s (open by default) --&gt;
      &lt;details open&gt;
        &lt;summary&gt;
          &lt;div class=&quot;tl-arrow&quot;&gt;&amp;#9656;&lt;/div&gt;
          &lt;div class=&quot;tl-decade&quot;&gt;2020s&lt;/div&gt;
          &lt;div class=&quot;tl-teaser&quot;&gt;New leadership. Lineup overhaul.&lt;/div&gt;
        &lt;/summary&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;2024&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;New Leadership&lt;/div&gt;
            &lt;p&gt;Maggie LePique, a music host at the station since the &amp;rsquo;90s, takes over as interim General Manager and begins refocusing on local journalism and community programming.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;tl-entry&quot;&gt;
          &lt;div class=&quot;tl-year&quot;&gt;2025&lt;/div&gt;
          &lt;div class=&quot;tl-content&quot;&gt;
            &lt;div&gt;Lineup Overhaul&lt;/div&gt;
            &lt;p&gt;KPFK restructures its programming, expanding local voices and pulling fringe content out of prime hours. Shows like &lt;em&gt;Background Briefing&lt;/em&gt; return to anchor the schedule.&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/details&gt;

    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;


&lt;!-- ==================== BLOCK 4: WHAT WE DO ==================== --&gt;
&lt;div id=&quot;what-we-do&quot; style=&quot;background:#fff; color:#1a1a1a; padding:3rem 1.5rem; font-family:Georgia,&#039;Times New Roman&#039;,serif; border-bottom:3px solid #e0e0e0;&quot;&gt;
  &lt;div style=&quot;max-width:800px; margin:0 auto;&quot;&gt;
    &lt;div style=&quot;font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-weight:900; font-size:1.8rem; text-transform:uppercase; letter-spacing:-0.02em; margin-bottom:0.5rem; line-height:1.1;&quot;&gt;What We Do&lt;/div&gt;
    &lt;p style=&quot;font-size:1.15rem; font-style:italic; margin:0 0 1.5rem 0; color:#555;&quot;&gt;We don&#039;t do soundbites. We do signal.&lt;/p&gt;
    &lt;p style=&quot;font-size:1.05rem; line-height:1.7; margin:0 0 1.5rem 0;&quot;&gt;KPFK is on the air 24 hours a day with reporting, music, and conversation you won&#039;t find anywhere else on the dial. We cover what matters to Southern California and what the rest of the media ignores.&lt;/p&gt;
    &lt;div style=&quot;border:3px solid #1a1a1a; margin-bottom:1.5rem;&quot;&gt;
      &lt;div style=&quot;padding:14px 16px; border-bottom:1px solid #e0e0e0; display:flex; gap:12px; align-items:baseline;&quot;&gt;
        &lt;div style=&quot;font-family:&#039;Courier New&#039;,monospace; font-size:11px; font-weight:700; text-transform:uppercase; color:#c41e3a; flex-shrink:0; min-width:24px;&quot;&gt;01&lt;/div&gt;
        &lt;div&gt;&lt;div style=&quot;font-family:&#039;Helvetica Neue&#039;,Helvetica,Arial,sans-serif; font-size:0.95rem; font-weight:900; text-transform:uppercase; display:inline;&quot;&gt;Investigative Journalism&lt;/div&gt;&lt;span style=&quot;color:#555; font-size:0.95rem;&quot;&gt; &amp;mdash; From Palestine to Pico-Union.&lt;/span&gt;&lt;/div&gt;
      &lt;/div&gt;
