const CLIPS = {
  &quot;alexander_bundle&quot;: [
    { title: &quot;The Thesis&quot;, duration: &quot;6:28&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1616e558f.mp3&quot;, intro: &quot;Michelle Alexander once saw a poster on a telephone pole in Oakland that said &#039;the drug war is the new Jim Crow.&#039; She thought it was crazy talk. After years as a civil rights lawyer at the ACLU, she realized she was dead wrong. WBAI recorded her at Abyssinian Baptist Church in Harlem, presenting the thesis of her book, The New Jim Crow.&quot; },
    { title: &quot;Designed to Fail&quot;, duration: &quot;4:53&quot;, url: &quot;https://mmo.aiircdn.com/237/697a162d26cab.mp3&quot;, intro: &quot;What happens after prison? You can&#039;t vote. You can&#039;t serve on a jury. You can be denied housing, employment, food stamps. In some states, your wages can be garnished one hundred percent. Seventy percent of people released from prison return within three years. The system is designed to fail. Here&#039;s Michelle Alexander at Abyssinian Baptist Church, recorded by WBAI.&quot; },
    { title: &quot;The Greatest Myth&quot;, duration: &quot;3:07&quot;, url: &quot;https://mmo.aiircdn.com/237/697a162a7ee7f.mp3&quot;, intro: &quot;What&#039;s the greatest myth about mass incarceration? Michelle Alexander says it&#039;s the idea that it has anything to do with crime. Eighty percent of Black men in Chicago have criminal records. Ninety percent in Washington, D.C. This is Alexander at Abyssinian Baptist Church, recorded by WBAI.&quot; },
    { title: &quot;Slept Through a Revolution&quot;, duration: &quot;2:59&quot;, url: &quot;https://mmo.aiircdn.com/237/697a161ece2be.mp3&quot;, intro: &quot;Dr. King warned us about sleeping through a revolution. Michelle Alexander says we did exactly that—we slept through a counter-revolution. This is Alexander speaking at Abyssinian Baptist Church, recorded by WBAI.&quot; },
    { title: &quot;More Than Were Enslaved&quot;, duration: &quot;2:46&quot;, url: &quot;https://mmo.aiircdn.com/237/697a161f624a1.mp3&quot;, intro: &quot;Michelle Alexander is the author of The New Jim Crow. WBAI recorded her at Abyssinian Baptist Church in Harlem. Here she is with some numbers that should stop you cold.&quot; },
    { title: &quot;Southern Strategy / Haldeman&quot;, duration: &quot;2:33&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1616cb7e1.mp3&quot;, intro: &quot;How was the war on drugs designed, and who was it designed to target? WBAI recorded Michelle Alexander speaking at Abyssinian Baptist Church in Harlem. Here she reads from Nixon&#039;s own chief of staff, H.R. Haldeman.&quot; }
  ],
  &quot;baldwin_bundle&quot;: [
    { title: &quot;Blow the Whistle (Extended)&quot;, duration: &quot;7:49&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1655be881.mp3&quot;, intro: &quot;In 1963, James Baldwin laid out a vision for massive civil disobedience—rent strikes, economic pressure on the power structure. And he rejected the red-baiting that tried to silence these conversations. &#039;I think it is beneath me to say that I&#039;m not a communist,&#039; he said. &#039;I think it&#039;s beneath the nation.&#039; This is from the Pacifica Radio Archives.&quot; },
    { title: &quot;Blow the Whistle&quot;, duration: &quot;4:33&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1647123ff.mp3&quot;, intro: &quot;This country has admired nonviolent protesters for years, James Baldwin says—applauded them, watched them get beaten with chains and hoses, and done nothing to help them. Here&#039;s Baldwin in 1963, from the Pacifica Radio Archives, saying it&#039;s time to blow the whistle.&quot; },
    { title: &quot;Never Wanted to Come (Extended)&quot;, duration: &quot;4:21&quot;, url: &quot;https://mmo.aiircdn.com/237/697a163a3285d.mp3&quot;, intro: &quot;From the Pacifica Radio Archives, here&#039;s James Baldwin in 1963 on America&#039;s founding myths, what really built this country, and how Black Americans can use their economic weight for liberation.&quot; },
    { title: &quot;Never Wanted to Come Here&quot;, duration: &quot;1:51&quot;, url: &quot;https://mmo.aiircdn.com/237/697a16388cee8.mp3&quot;, intro: &quot;The Pacifica Radio Archives holds an extraordinary collection of James Baldwin speeches from 1963 and &#039;64. Here&#039;s Baldwin cutting through the myths about who built America—and who never wanted to come here in the first place.&quot; },
    { title: &quot;We the People&quot;, duration: &quot;0:23&quot;, url: &quot;https://mmo.aiircdn.com/237/697a162c82f99.mp3&quot;, intro: &quot;James Baldwin, from the Pacifica Radio Archives, 1963.&quot; }
  ],
  &quot;davis_bundle&quot;: [
    { title: &quot;I Was Never Alone&quot;, duration: &quot;3:31&quot;, url: &quot;https://mmo.aiircdn.com/237/697a160e5d1c1.mp3&quot;, intro: &quot;In 1970, Angela Davis was on the FBI&#039;s Ten Most Wanted list. She faced three capital charges. The campaign to free her became a global movement—church folks, trade unions, communists, Democrats, people all over the world. In 2010, KPFK recorded her speaking in Watts, reflecting on what that movement taught her. This is Angela Davis.&quot; },
    { title: &quot;Haiti: The Only Successful Uprising&quot;, duration: &quot;3:19&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1655b31f5.mp3&quot;, intro: &quot;When we talk about Black history, we often leave out the most important chapter. In 2010, KPFK recorded Angela Davis speaking in Watts. Here she is on Haiti—the only successful slave uprising in all of history—and what the civil rights movement was really about.&quot; },
    { title: &quot;Surveillance (Extended)&quot;, duration: &quot;2:29&quot;, url: &quot;https://mmo.aiircdn.com/237/697a161163192.mp3&quot;, intro: &quot;Angela Davis was speaking in Watts in 2010 at an event organized by Susan Burton&#039;s A New Way of Life—a reentry program for formerly incarcerated women. Here&#039;s Davis on how surveillance in Black communities produces the racial disparities we see in our prisons. This is from KPFK.&quot; },
    { title: &quot;Freedom as Mandela Taught Us&quot;, duration: &quot;1:46&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1657ebea4.mp3&quot;, intro: &quot;In 2010, KPFK recorded Angela Davis in Watts at an event hosted by Susan Burton&#039;s A New Way of Life. Here&#039;s Davis on what Nelson Mandela taught us about freedom—it&#039;s not a destination, it&#039;s a struggle.&quot; },
    { title: &quot;Surveillance &amp; Criminalization&quot;, duration: &quot;1:25&quot;, url: &quot;https://mmo.aiircdn.com/237/697a16596db60.mp3&quot;, intro: &quot;Why do some communities fill our prisons while others don&#039;t? In 2010, KPFK recorded Angela Davis speaking in Watts. Here she breaks down the simple logic most people miss.&quot; },
    { title: &quot;LGBT Struggle&quot;, duration: &quot;0:19&quot;, url: &quot;https://mmo.aiircdn.com/237/697a1649a5dbd.mp3&quot;, intro: &quot;Angela Davis, speaking in Watts in 2010, on why freedom movements must be inclusive.&quot; },
    { title: &quot;Inhabiting History&quot;, duration: &quot;0:14&quot;, url: &quot;https://mmo.aiircdn.com/237/697a16071a30d.mp3&quot;, intro: &quot;In 2010, KPFK recorded Angela Davis speaking in Watts at the Labor Community Action Committee. Here she is on why Black history isn&#039;t just about the past.&quot; },
    { title: &quot;We Are the Ones&quot;, duration: &quot;0:11&quot;, url: &quot;https://mmo.aiircdn.com/237/697a16576f2b7.mp3&quot;, intro: &quot;Angela Davis, recorded by KPFK in Watts in 2010.&quot; }
  ]
  // Note: Malcolm X, Parks, Hamer clips not yet uploaded to aiircdn
};

