function closeLightbox() {
  // Pause any playing audio in lightbox
  document.querySelectorAll(&#039;#bhm-lightbox audio&#039;).forEach(a =&gt; a.pause());
  document.getElementById(&#039;bhm-lightbox&#039;).classList.remove(&#039;open&#039;);
  document.body.style.overflow = &#039;&#039;;
}

// Close on backdrop click
document.getElementById(&#039;bhm-lightbox&#039;).addEventListener(&#039;click&#039;, function(e) {
  if (e.target === this) closeLightbox();
});

// Close on Escape key
document.addEventListener(&#039;keydown&#039;, function(e) {
  if (e.key === &#039;Escape&#039;) closeLightbox();
});

// Copy tracklist to clipboard
function copyTracklist(premiumId) {
  const tracklist = TRACKLISTS[premiumId];
  if (!tracklist) return;

  const text = tracklist.map(disc =&gt; {
    return disc.disc + &#039;\n&#039; + disc.tracks.map(t =&gt; &#039;• &#039; + t).join(&#039;\n&#039;);
  }).join(&#039;\n\n&#039;);

  navigator.clipboard.writeText(text).then(() =&gt; {
    const btn = document.querySelector(&#039;.bhm-tracklist-copy&#039;);
    if (btn) {
      btn.textContent = &#039;✓ Copied&#039;;
      btn.classList.add(&#039;copied&#039;);
      setTimeout(() =&gt; {
        btn.textContent = &#039;📋 Copy&#039;;
        btn.classList.remove(&#039;copied&#039;);
      }, 2000);
    }
  });
}

// Open lightbox and scroll to tracklist
function openTracklistLightbox(premiumId) {
  openLightbox(premiumId);
  setTimeout(() =&gt; {
    const tracklistSection = document.getElementById(&#039;bhm-tracklist-section&#039;);
    if (tracklistSection) {
      tracklistSection.scrollIntoView({ behavior: &#039;smooth&#039;, block: &#039;start&#039; });
    }
  }, 100);
}

// Download function that actually downloads
function downloadClip(url, filename) {
  fetch(url)
    .then(response =&gt; response.blob())
    .then(blob =&gt; {
      const link = document.createElement(&#039;a&#039;);
      link.href = URL.createObjectURL(blob);
      link.download = filename || url.split(&#039;/&#039;).pop();
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(link.href);
    })
    .catch(err =&gt; {
      console.error(&#039;Download failed:&#039;, err);
      // Fallback: open in new tab
      window.open(url, &#039;_blank&#039;);
    });
}

// Now Playing Bar
let currentAudio = null;
let currentPremiumId = null;
let timeUpdateInterval = null;

function formatTime(seconds) {
  if (isNaN(seconds) || !isFinite(seconds)) return &#039;0:00&#039;;
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, &#039;0&#039;)}`;
}

function showNowPlaying(audio, title, premiumId) {
  // Remove previous highlight
  document.querySelectorAll(&#039;.bhm-premium-card.now-playing&#039;).forEach(c =&gt; c.classList.remove(&#039;now-playing&#039;));

  currentAudio = audio;
  currentPremiumId = premiumId;

  // Add highlight to current card
  if (premiumId) {
    const card = document.querySelector(`[data-premium-id=&quot;${premiumId}&quot;]`);
    if (card) card.classList.add(&#039;now-playing&#039;);
  }

  document.getElementById(&#039;bhm-np-title&#039;).textContent = title;
  document.getElementById(&#039;bhm-now-playing&#039;).classList.add(&#039;visible&#039;);

  // Update time display
  updateTimeDisplay();
  if (timeUpdateInterval) clearInterval(timeUpdateInterval);
  timeUpdateInterval = setInterval(updateTimeDisplay, 250);
}

function updateTimeDisplay() {
  if (!currentAudio) return;
  const elapsed = formatTime(currentAudio.currentTime);
  const total = formatTime(currentAudio.duration);
  document.getElementById(&#039;bhm-np-time&#039;).textContent = `${elapsed} / ${total}`;
}

function hideNowPlaying() {
  // Remove highlight from any card and clip
  document.querySelectorAll(&#039;.bhm-premium-card.now-playing&#039;).forEach(c =&gt; c.classList.remove(&#039;now-playing&#039;));
  document.querySelectorAll(&#039;.bhm-clip.now-playing&#039;).forEach(c =&gt; c.classList.remove(&#039;now-playing&#039;));

  document.getElementById(&#039;bhm-now-playing&#039;).classList.remove(&#039;visible&#039;);
  if (timeUpdateInterval) {
    clearInterval(timeUpdateInterval);
    timeUpdateInterval = null;
  }
  currentAudio = null;
  currentPremiumId = null;
}

function stopCurrentAudio() {
  if (currentAudio) {
    currentAudio.pause();
    currentAudio.currentTime = 0;
  }
  hideNowPlaying();
}

function scrollToCard(premiumId) {
  // Close lightbox if open
  closeLightbox();

  // Find the card
  const card = document.querySelector(`[data-premium-id=&quot;${premiumId}&quot;]`);
  if (card) {
    // Expand the audio section if collapsed
    const toggle = card.querySelector(&#039;.bhm-audio-toggle&#039;);
    const audioList = card.querySelector(&#039;.bhm-audio-list&#039;);
    if (toggle &amp;&amp; audioList &amp;&amp; !toggle.classList.contains(&#039;open&#039;)) {
      toggle.classList.add(&#039;open&#039;);
      audioList.classList.add(&#039;open&#039;);
    }

    // Find the playing clip within this card and scroll to it
    const playingClip = card.querySelector(&#039;.bhm-clip.now-playing&#039;);
    if (playingClip) {
      // Small delay to let the dropdown expand
      setTimeout(() =&gt; {
        playingClip.scrollIntoView({ behavior: &#039;smooth&#039;, block: &#039;center&#039; });
      }, 100);
    } else {
      card.scrollIntoView({ behavior: &#039;smooth&#039;, block: &#039;center&#039; });
    }
  }
}

