function applyFilter(query) {
  const q = query.toLowerCase().trim();
  const tokens = q.split(/\s+/).filter(t =&gt; t.length &gt; 0);
  const cards = document.querySelectorAll(&#039;.bhm-premium-card&#039;);
  let visibleCount = 0;

  cards.forEach(card =&gt; {
    const premiumId = card.dataset.premiumId;
    const searchText = SEARCH_TERMS[premiumId] || &#039;&#039;;
    // All tokens must match
    const matches = tokens.length === 0 || tokens.every(token =&gt; searchText.includes(token));

    if (matches) {
      card.classList.remove(&#039;filtered-out&#039;);
      visibleCount++;
    } else {
      card.classList.add(&#039;filtered-out&#039;);
    }
  });

  // Hide empty tier headers
  document.querySelectorAll(&#039;.bhm-tier-header&#039;).forEach(header =&gt; {
    const grid = header.nextElementSibling;
    if (grid &amp;&amp; grid.classList.contains(&#039;bhm-premium-grid&#039;)) {
      const visibleCards = grid.querySelectorAll(&#039;.bhm-premium-card:not(.filtered-out)&#039;);
      if (visibleCards.length === 0) {
        header.classList.add(&#039;empty-tier&#039;);
      } else {
        header.classList.remove(&#039;empty-tier&#039;);
      }
    }
  });

  // Update UI
  filterClear.classList.toggle(&#039;visible&#039;, q.length &gt; 0);
  if (q) {
    filterCount.textContent = `${visibleCount} of 18`;
  } else {
    filterCount.textContent = &#039;&#039;;
  }
}

filterInput.addEventListener(&#039;input&#039;, function() {
  applyFilter(this.value);
});

filterClear.addEventListener(&#039;click&#039;, function() {
  filterInput.value = &#039;&#039;;
  applyFilter(&#039;&#039;);
  filterInput.focus();
});

(function() {
  &#039;use strict&#039;;

  // Auto-pause other audio when one starts, show now playing bar
  document.addEventListener(&#039;play&#039;, function(e) {
    if (e.target.tagName === &#039;AUDIO&#039;) {
      // Pause others
      document.querySelectorAll(&#039;audio&#039;).forEach(audio =&gt; {
        if (audio !== e.target) audio.pause();
      });

      // Remove previous clip highlights
      document.querySelectorAll(&#039;.bhm-clip.now-playing&#039;).forEach(c =&gt; c.classList.remove(&#039;now-playing&#039;));

      // Get clip info
      const clipEl = e.target.closest(&#039;.bhm-clip&#039;);
      const cardEl = e.target.closest(&#039;.bhm-premium-card&#039;) || document.querySelector(&#039;.bhm-lightbox-content&#039;);
      let title = &#039;Playing...&#039;;
      let premiumId = null;

      if (clipEl) {
        clipEl.classList.add(&#039;now-playing&#039;);
        const titleEl = clipEl.querySelector(&#039;.bhm-clip-title&#039;);
        if (titleEl) title = titleEl.textContent;
      }

      if (cardEl &amp;&amp; cardEl.dataset &amp;&amp; cardEl.dataset.premiumId) {
        premiumId = cardEl.dataset.premiumId;
      } else {
        // Check if in lightbox - find from URL
        const audioSrc = e.target.src;
        for (const [pid, clips] of Object.entries(CLIPS)) {
          if (clips.some(c =&gt; c.url === audioSrc)) {
            premiumId = pid;
            break;
          }
        }
      }

      showNowPlaying(e.target, title, premiumId);
    }
  }, true);

  // Hide bar only when audio ends (not on pause)
  document.addEventListener(&#039;ended&#039;, function(e) {
    if (e.target.tagName === &#039;AUDIO&#039;) {
      hideNowPlaying();
    }
  }, true);

  const renderClips = (premiumId) =&gt; {
    const clips = CLIPS[premiumId];
    if (!clips || clips.length === 0) {
      return &#039;&lt;div class=&quot;bhm-no-clips&quot;&gt;Preview clips not yet uploaded — full audio included with premium&lt;/div&gt;&#039;;
    }

    return clips.map(clip =&gt; {
      const safeFilename = clip.title.replace(/[^a-z0-9]/gi, &#039;_&#039;).toLowerCase() + &#039;.mp3&#039;;
      return `
      &lt;div class=&quot;bhm-clip&quot;&gt;
        &lt;div class=&quot;bhm-clip-header&quot;&gt;
          &lt;span class=&quot;bhm-clip-title&quot;&gt;${clip.title}&lt;/span&gt;
          &lt;span class=&quot;bhm-clip-duration&quot;&gt;${clip.duration}&lt;/span&gt;
        &lt;/div&gt;
        &lt;div class=&quot;bhm-clip-intro&quot;&gt;${clip.intro}&lt;/div&gt;
        &lt;div class=&quot;bhm-clip-controls&quot;&gt;
          &lt;audio controls preload=&quot;none&quot; src=&quot;${clip.url}&quot;&gt;&lt;/audio&gt;
          &lt;button class=&quot;bhm-download-btn&quot; onclick=&quot;downloadClip(&#039;${clip.url}&#039;, &#039;${safeFilename}&#039;)&quot; title=&quot;Download clip&quot;&gt;↓ DL&lt;/button&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    `}).join(&#039;&#039;);
  };

  const renderCard = (p) =&gt; {
    const contents = p.contents.split(&#039;|&#039;);
    const isCollection = p.tier === &#039;Collection&#039;;
    const isPending = p.status === &#039;pending&#039;;
    const clips = CLIPS[p.id] || [];
    const clipCount = clips.length;
    const hasClips = clipCount &gt; 0;
    const hasTracklist = !!TRACKLISTS[p.id];

    return `&lt;div class=&quot;bhm-premium-card ${isCollection ? &#039;collection&#039; : &#039;&#039;} ${isPending ? &#039;pending&#039; : &#039;&#039;}&quot; data-tier=&quot;${p.tier.toLowerCase()}&quot; data-price=&quot;${p.price}&quot; data-premium-id=&quot;${p.id}&quot;&gt;
      &lt;div class=&quot;bhm-card-header&quot; onclick=&quot;openLightbox(&#039;${p.id}&#039;)&quot; style=&quot;cursor:pointer;&quot; title=&quot;Click to expand&quot;&gt;
        &lt;div class=&quot;bhm-card-header-left&quot;&gt;
          &lt;div class=&quot;bhm-card-name&quot;&gt;${p.name}&lt;/div&gt;
          &lt;span class=&quot;bhm-card-tier&quot;&gt;${p.tier}${isPending ? &#039; — PENDING&#039; : &#039;&#039;}&lt;/span&gt;
        &lt;/div&gt;
        &lt;span class=&quot;bhm-card-price&quot;&gt;$${p.price}&lt;/span&gt;
      &lt;/div&gt;
      &lt;div class=&quot;bhm-card-body&quot;&gt;
        &lt;div class=&quot;bhm-card-top&quot;&gt;
          ${p.image ? `&lt;img class=&quot;bhm-card-image&quot; src=&quot;${p.image}&quot; alt=&quot;${p.name}&quot; onclick=&quot;openLightbox(&#039;${p.id}&#039;)&quot; title=&quot;Click to expand&quot;&gt;` : &#039;&lt;div class=&quot;bhm-card-image no-image&quot;&gt;No image&lt;/div&gt;&#039;}
          &lt;div class=&quot;bhm-card-info&quot;&gt;
            &lt;div class=&quot;bhm-card-creator&quot;&gt;${p.creator}&lt;/div&gt;
            &lt;div class=&quot;bhm-card-primary-title&quot;&gt;${p.primaryTitle}&lt;/div&gt;
            &lt;span class=&quot;bhm-card-label&quot;&gt;${p.label}&lt;/span&gt;${hasTracklist ? `&lt;button class=&quot;bhm-tracklist-btn&quot; onclick=&quot;event.stopPropagation(); openTracklistLightbox(&#039;${p.id}&#039;)&quot;&gt;🎵 Tracklist&lt;/button&gt;` : &#039;&#039;}
            &lt;ul class=&quot;bhm-card-contents&quot;&gt;${contents.map(c =&gt; `&lt;li&gt;${c.trim()}&lt;/li&gt;`).join(&#039;&#039;)}&lt;/ul&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;bhm-card-pitch&quot;&gt;${p.pitch}&lt;/div&gt;
      &lt;/div&gt;
      &lt;div class=&quot;bhm-audio-section&quot;&gt;
        &lt;button class=&quot;bhm-audio-toggle&quot; onclick=&quot;this.classList.toggle(&#039;open&#039;); this.nextElementSibling.classList.toggle(&#039;open&#039;);&quot;&gt;
          &lt;span&gt;▶ ON-AIR CLIPS&lt;/span&gt;
          &lt;span class=&quot;clip-count&quot;&gt;${hasClips ? clipCount + &#039; clips ready&#039; : &#039;coming soon&#039;}&lt;/span&gt;
          &lt;span class=&quot;arrow&quot;&gt;▼&lt;/span&gt;
        &lt;/button&gt;
        &lt;div class=&quot;bhm-audio-list&quot;&gt;
          ${renderClips(p.id)}
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;`;
  };

  const renderByTier = (premiums, filter) =&gt; {
    let filtered = premiums;
    if (filter !== &#039;all&#039;) {
      filtered = premiums.filter(p =&gt; p.tier.toLowerCase() === filter);
    }

    const collections = filtered.filter(p =&gt; p.tier === &#039;Collection&#039;).sort((a, b) =&gt; b.price - a.price);
    const bundles = filtered.filter(p =&gt; p.tier === &#039;Bundle&#039;).sort((a, b) =&gt; b.price - a.price);

    let html = &#039;&#039;;
    if (collections.length &amp;&amp; (filter === &#039;all&#039; || filter === &#039;collection&#039;)) {
      html += `&lt;div class=&quot;bhm-tier-header&quot;&gt;Collections ($150–$200) &lt;span class=&quot;bhm-tier-count&quot;&gt;${collections.length} items&lt;/span&gt;&lt;/div&gt;`;
      html += `&lt;div class=&quot;bhm-premium-grid&quot;&gt;${collections.map(renderCard).join(&#039;&#039;)}&lt;/div&gt;`;
    }
    if (bundles.length &amp;&amp; (filter === &#039;all&#039; || filter === &#039;bundle&#039;)) {
      html += `&lt;div class=&quot;bhm-tier-header&quot;&gt;Bundles ($75–$100) &lt;span class=&quot;bhm-tier-count&quot;&gt;${bundles.length} items&lt;/span&gt;&lt;/div&gt;`;
      html += `&lt;div class=&quot;bhm-premium-grid&quot;&gt;${bundles.map(renderCard).join(&#039;&#039;)}&lt;/div&gt;`;
    }
    return html;
  };

  const renderSorted = (premiums, sortKey, filter) =&gt; {
    let filtered = premiums;
    if (filter !== &#039;all&#039;) {
      filtered = premiums.filter(p =&gt; p.tier.toLowerCase() === filter);
    }

    let sorted;
    if (sortKey === &#039;price-asc&#039;) {
      sorted = [...filtered].sort((a, b) =&gt; a.price - b.price);
    } else if (sortKey === &#039;price-desc&#039;) {
      sorted = [...filtered].sort((a, b) =&gt; b.price - a.price);
    } else {
      return renderByTier(filtered, filter);
    }

    return `&lt;div class=&quot;bhm-premium-grid&quot;&gt;${sorted.map(renderCard).join(&#039;&#039;)}&lt;/div&gt;`;
  };

  let currentSort = &#039;tier&#039;;
  let currentFilter = &#039;all&#039;;

  const render = () =&gt; {
    const container = document.getElementById(&#039;bhm-content&#039;);
    if (currentSort === &#039;tier&#039;) {
      container.innerHTML = renderByTier(PREMIUMS, currentFilter);
    } else {
      container.innerHTML = renderSorted(PREMIUMS, currentSort, currentFilter);
    }

    let filtered = PREMIUMS;
    if (currentFilter !== &#039;all&#039;) {
      filtered = PREMIUMS.filter(p =&gt; p.tier.toLowerCase() === currentFilter);
    }
    document.querySelector(&#039;.bhm-summary&#039;).textContent = `${filtered.length} premiums`;

    // Reapply text filter if active
    const filterVal = document.getElementById(&#039;bhm-filter-input&#039;).value;
    if (filterVal) {
      applyFilter(filterVal);
    }
  };

  document.querySelectorAll(&#039;.bhm-sort-btn&#039;).forEach(btn =&gt; {
    btn.addEventListener(&#039;click&#039;, () =&gt; {
      document.querySelectorAll(&#039;.bhm-sort-btn&#039;).forEach(b =&gt; b.classList.remove(&#039;active&#039;));
      btn.classList.add(&#039;active&#039;);
      currentSort = btn.dataset.sort;
      render();
    });
  });

  document.querySelectorAll(&#039;.bhm-filter-btn&#039;).forEach(btn =&gt; {
    btn.addEventListener(&#039;click&#039;, () =&gt; {
      document.querySelectorAll(&#039;.bhm-filter-btn&#039;).forEach(b =&gt; b.classList.remove(&#039;active&#039;));
      btn.classList.add(&#039;active&#039;);
      currentFilter = btn.dataset.filter;
      render();
    });
  });

  if (document.readyState === &#039;loading&#039;) {
    document.addEventListener(&#039;DOMContentLoaded&#039;, render);
  } else {
    render();
  }
})();
&lt;/script&gt;

