&lt;!DOCTYPE html&gt;
&lt;html lang=&quot;en&quot;&gt;
&lt;head&gt;
  &lt;meta charset=&quot;UTF-8&quot;&gt;
  &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0, viewport-fit=cover&quot;&gt;
  &lt;title&gt;KPFK 90.7 FM – Welcome&lt;/title&gt;
  &lt;link rel=&quot;preconnect&quot; href=&quot;https://fonts.googleapis.com&quot;&gt;
  &lt;link rel=&quot;preconnect&quot; href=&quot;https://fonts.gstatic.com&quot; crossorigin&gt;
  &lt;link href=&quot;https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&amp;family=Playfair+Display:wght@700;800&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;
  &lt;style&gt;
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    /* Hide domain-wide fund drive banner */
    #kpfk-fund-banner {
      display: none !important;
    }

    :root {
      --kpfk-red: #a30018;
      --kpfk-red-dark: #8a0014;
      --kpfk-red-glow: rgba(163, 0, 24, 0.15);
      --cream: #faf8f5;
      --cream-dark: #f0ebe3;
      --ink: #1a1612;
      --ink-muted: #5c544a;
      --ink-light: #8a8279;
      --radius: 12px;
      --radius-sm: 8px;
    }

    html {
      font-size: 16px;
      -webkit-text-size-adjust: 100%;
    }

    body {
      font-family: &#039;DM Sans&#039;, -apple-system, BlinkMacSystemFont, sans-serif;
      background: var(--cream);
      color: var(--ink);
      line-height: 1.5;
      min-height: 100dvh;
      overflow-x: hidden;
    }

    .page {
      max-width: 480px;
      margin: 0 auto;
      min-height: 100dvh;
      display: flex;
      flex-direction: column;
    }

    /* ============ HEADER ============ */
    .header {
      background: var(--kpfk-red);
      color: white;
      padding: 28px 24px 32px;
      text-align: center;
      position: relative;
      overflow: hidden;
    }

    /* Broadcast wave decoration */
    .header::before {
      content: &#039;&#039;;
      position: absolute;
      top: 50%;
      left: 50%;
      width: 300px;
      height: 300px;
      transform: translate(-50%, -50%);
      background: 
        radial-gradient(circle, transparent 30%, rgba(255,255,255,0.05) 31%, rgba(255,255,255,0.05) 32%, transparent 33%),
        radial-gradient(circle, transparent 50%, rgba(255,255,255,0.04) 51%, rgba(255,255,255,0.04) 52%, transparent 53%),
        radial-gradient(circle, transparent 70%, rgba(255,255,255,0.03) 71%, rgba(255,255,255,0.03) 72%, transparent 73%);
      animation: broadcast 3s ease-in-out infinite;
      pointer-events: none;
    }

    @keyframes broadcast {
      0%, 100% { opacity: 0.6; transform: translate(-50%, -50%) scale(0.95); }
      50% { opacity: 1; transform: translate(-50%, -50%) scale(1.05); }
    }

    .header-content {
      position: relative;
      z-index: 1;
    }

    .header h1 {
      font-family: &#039;DM Sans&#039;, -apple-system, BlinkMacSystemFont, sans-serif;
      font-size: 26px;
      font-weight: 600;
      line-height: 1.2;
      margin-bottom: 6px;
    }

    .tagline {
      font-size: 15px;
      opacity: 0.9;
      font-weight: 400;
    }

    /* ============ PRIMARY ACTIONS ============ */
    .actions {
      padding: 28px 20px 24px;
      background: white;
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .btn {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      padding: 16px 20px;
      border-radius: var(--radius);
      text-decoration: none;
      font-weight: 600;
      font-size: 17px;
      transition: all 0.15s ease;
      -webkit-tap-highlight-color: transparent;
      touch-action: manipulation;
      border: none;
      cursor: pointer;
    }

    .btn svg {
      width: 20px;
      height: 20px;
      flex-shrink: 0;
    }

    .btn-primary {
      background: var(--kpfk-red);
      color: white;
      box-shadow: 0 2px 8px rgba(163, 0, 24, 0.25);
    }

    .btn-primary:active {
      background: var(--kpfk-red-dark);
      transform: scale(0.98);
    }

    .btn-secondary {
      background: var(--cream);
      color: var(--ink);
      border: 1.5px solid var(--cream-dark);
    }

    .btn-secondary:active {
      background: var(--cream-dark);
      transform: scale(0.98);
    }

    /* Two-column grid for secondary buttons */
    .btn-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 12px;
    }

    .btn-grid .btn {
      font-size: 15px;
      padding: 14px 12px;
    }

    /* ============ QUICK LINKS ============ */
    .links-section {
      padding: 24px 20px;
      background: var(--cream);
    }

    .section-label {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      color: var(--ink-light);
      margin-bottom: 16px;
      text-align: center;
    }

    .link-list {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 8px 16px;
      list-style: none;
    }

    .link-list a {
      color: var(--ink-muted);
      text-decoration: none;
      font-size: 14px;
      font-weight: 500;
      padding: 6px 4px;
      transition: color 0.15s ease;
    }

    .link-list a:active {
      color: var(--kpfk-red);
    }

    /* ============ CONTACT ROW ============ */
    .contact-row {
      display: flex;
      gap: 12px;
      padding: 0 20px 24px;
      background: var(--cream);
    }

    .contact-btn {
      flex: 1;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      padding: 14px 12px;
      background: white;
      border: 1px solid var(--cream-dark);
      border-radius: var(--radius-sm);
      text-decoration: none;
      color: var(--ink);
      font-size: 14px;
      font-weight: 500;
      transition: all 0.15s ease;
      -webkit-tap-highlight-color: transparent;
    }

    .contact-btn:active {
      background: var(--cream);
      transform: scale(0.98);
    }

    .contact-btn svg {
      width: 18px;
      height: 18px;
      color: var(--kpfk-red);
    }

    /* ============ MAIL DONATION ============ */
    .mail-section {
      padding: 20px;
      background: white;
      border-top: 1px solid var(--cream-dark);
    }

    .mail-card {
      background: linear-gradient(135deg, var(--cream) 0%, white 100%);
      border: 1px dashed var(--ink-light);
      border-radius: var(--radius);
      padding: 20px;
      text-align: center;
    }

    .mail-card-label {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      color: var(--ink-light);
      margin-bottom: 12px;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
    }

    .mail-card-label svg {
      width: 14px;
      height: 14px;
    }

    .mail-address {
      font-size: 14px;
      color: var(--ink);
      line-height: 1.6;
    }

    .mail-address strong {
      display: block;
      font-weight: 600;
      margin-bottom: 2px;
    }

    .copy-btn {
      margin-top: 14px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 10px 16px;
      font-size: 13px;
      font-weight: 600;
      color: var(--kpfk-red);
      background: white;
      border: 1.5px solid var(--kpfk-red);
      border-radius: var(--radius-sm);
      cursor: pointer;
      transition: all 0.15s ease;
      -webkit-tap-highlight-color: transparent;
    }

    .copy-btn:active {
      background: var(--kpfk-red);
      color: white;
    }

    .copy-btn svg {
      width: 14px;
      height: 14px;
    }

    .copy-btn.copied {
      background: var(--kpfk-red);
      color: white;
    }

    /* ============ SOCIAL ============ */
    .social-section {
      padding: 24px 20px 32px;
      background: var(--cream);
      text-align: center;
    }

    .social-row {
      display: flex;
      justify-content: center;
      gap: 16px;
      margin-top: 16px;
    }

    .social-link {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 44px;
      height: 44px;
      border-radius: 50%;
      background: white;
      color: var(--ink-muted);
      border: 1px solid var(--cream-dark);
      transition: all 0.15s ease;
      -webkit-tap-highlight-color: transparent;
    }

    .social-link:active {
      background: var(--kpfk-red);
      color: white;
      border-color: var(--kpfk-red);
      transform: scale(0.95);
    }

    .social-link svg {
      width: 20px;
      height: 20px;
      fill: currentColor;
    }

    /* ============ FOOTER ============ */
    .footer {
      padding: 24px 20px 28px;
      text-align: center;
      background: var(--cream);
      margin-top: auto;
    }

    .footer-logo {
      height: 40px;
      width: auto;
      margin-bottom: 12px;
    }

    .footer-text {
      font-size: 12px;
      color: var(--ink-light);
    }

    /* Safe area for notched phones */
    @supports (padding-bottom: env(safe-area-inset-bottom)) {
      .footer {
        padding-bottom: calc(20px + env(safe-area-inset-bottom));
      }
    }
  &lt;/style&gt;
