                &lt;div&gt;Wednesday&lt;/div&gt;
                &lt;div&gt;Thursday&lt;/div&gt;
                &lt;div&gt;Friday&lt;/div&gt;
                &lt;div&gt;Saturday&lt;/div&gt;
            &lt;/div&gt;
            
            &lt;div id=&quot;kpfkContent&quot;&gt;
                &lt;!-- 48 time slots per day (30-minute intervals) will be generated here --&gt;
            &lt;/div&gt;
        &lt;/div&gt;
        
        &lt;div class=&quot;kpfk-legend&quot; id=&quot;kpfkLegend&quot;&gt;
            &lt;h3&gt;Legend&lt;/h3&gt;
