                &lt;span&gt;Current Time Slot&lt;/span&gt;
            &lt;/div&gt;
            &lt;div class=&quot;kpfk-legend-item&quot;&gt;
                &lt;div class=&quot;kpfk-legend-indicator kpfk-legend-offline&quot;&gt;&lt;/div&gt;
                &lt;span&gt;Data Unavailable&lt;/span&gt;
            &lt;/div&gt;
            &lt;div class=&quot;kpfk-updated&quot; id=&quot;kpfkUpdated&quot;&gt;
                &lt;!-- Connection status will be shown here --&gt;
            &lt;/div&gt;
