&lt;script&gt;
window.KPFKSchedule = (function() {
    &#039;use strict&#039;;
    
    // Configuration
    const KPFK_SCHEDULE_URL = &#039;https://confessor.kpfk.org/playlist/pub_sched.php&#039;;
    const DAYS = [&#039;Sunday&#039;, &#039;Monday&#039;, &#039;Tuesday&#039;, &#039;Wednesday&#039;, &#039;Thursday&#039;, &#039;Friday&#039;, &#039;Saturday&#039;];
    const REFRESH_INTERVAL = 600000; // 10 minutes
    
    // State
    let scheduleData = {};
    let connectionStatus = &#039;disconnected&#039;;
    let lastError = null;
    let refreshTimer = null;
    
    // Error tracking
    const errorCodes = {
        CORS_BLOCKED: &#039;CORS_BLOCKED - Browser blocking cross-origin request&#039;,
        NETWORK_ERROR: &#039;NETWORK_ERROR - Cannot reach confessor.kpfk.org&#039;,
        TIMEOUT: &#039;TIMEOUT - Request timed out after 10 seconds&#039;,
        HTTP_ERROR: &#039;HTTP_ERROR - Server returned error status&#039;,
        PARSE_ERROR: &#039;PARSE_ERROR - Cannot parse schedule data&#039;,
        NO_DATA: &#039;NO_DATA - Schedule container not found in response&#039;
    };
    
    // Utilities
    function updateStatus(status, message) {
        try {
            const statusDot = document.getElementById(&#039;kpfkStatusDot&#039;);
            const statusText = document.getElementById(&#039;kpfkStatusText&#039;);
            if (statusDot &amp;&amp; statusText) {
                statusDot.className = &#039;kpfk-status-dot &#039; + (status || &#039;&#039;);
                statusText.textContent = message || &#039;&#039;;
            }
            connectionStatus = status;
        } catch (e) {
            console.warn(&#039;Status update failed:&#039;, e);
        }
    }
    
    function showElement(id) {
        try {
            const el = document.getElementById(id);
            if (el) el.style.display = &#039;block&#039;;
        } catch (e) {
            console.warn(&#039;Show element failed:&#039;, e);
        }
    }
    
    function hideElement(id) {
        try {
            const el = document.getElementById(id);
            if (el) el.style.display = &#039;none&#039;;
        } catch (e) {
            console.warn(&#039;Hide element failed:&#039;, e);
        }
    }
    
    function formatTime(hour, minute = 0) {
        const ampm = hour &gt;= 12 ? &#039;PM&#039; : &#039;AM&#039;;
        const hour12 = hour === 0 ? 12 : hour &gt; 12 ? hour - 12 : hour;
        const minuteStr = minute.toString().padStart(2, &#039;0&#039;);
        return hour12 + &#039;:&#039; + minuteStr + &#039; &#039; + ampm;
    }
    
    function generateTimeSlots() {
        // Create 48 slots: 24 hours × 2 (30-minute intervals)
        const slots = [];
        for (let hour = 0; hour &lt; 24; hour++) {
            // Top of hour
            slots.push({ 
                time: hour * 3600, 
                display: formatTime(hour, 0), 
                isHour: true 
            });
            // Half hour
            slots.push({ 
                time: hour * 3600 + 1800, 
                display: formatTime(hour, 30), 
                isHour: false 
            });
        }
        return slots;
    }
    
    function isCurrentTimeSlot(dayIndex, timeSeconds) {
        const now = new Date();
        const currentDay = now.getDay();
        const currentTime = now.getHours() * 3600 + now.getMinutes() * 60;
        return dayIndex === currentDay &amp;&amp; timeSeconds &lt;= currentTime &amp;&amp; currentTime &lt; timeSeconds + 1800;
    }
    
    function showError(errorType, details) {
        lastError = { type: errorType, details: details, timestamp: new Date() };
        
        hideElement(&#039;kpfkLoading&#039;);
        hideElement(&#039;kpfkGrid&#039;);
        showElement(&#039;kpfkError&#039;);
        
        const errorMessage = document.getElementById(&#039;kpfkErrorMessage&#039;);
        const errorCode = document.getElementById(&#039;kpfkErrorCode&#039;);
        
        if (errorMessage) {
            errorMessage.textContent = `Unable to load schedule from KPFK servers.`;
        }
        
        if (errorCode) {
            errorCode.innerHTML = `
                &lt;strong&gt;${errorCodes[errorType] || errorType}&lt;/strong&gt;&lt;br&gt;
                Details: ${details}&lt;br&gt;
                Time: ${lastError.timestamp.toLocaleTimeString()}&lt;br&gt;
                URL: ${KPFK_SCHEDULE_URL}
            `;
        }
        
        updateStatus(&#039;error&#039;, &#039;Connection failed&#039;);
    }
    
    function generateEmptyGrid() {
        try {
            const content = document.getElementById(&#039;kpfkContent&#039;);
            if (!content) return;
            
            content.innerHTML = &#039;&#039;;
            const timeSlots = generateTimeSlots();
            
            timeSlots.forEach(slot =&gt; {
                const timeSlot = document.createElement(&#039;div&#039;);
                timeSlot.className = &#039;kpfk-time-slot&#039;;
                
                const timeLabel = document.createElement(&#039;div&#039;);
                timeLabel.className = slot.isHour ? &#039;kpfk-time-label hour&#039; : &#039;kpfk-time-label&#039;;
                timeLabel.textContent = slot.display;
                timeSlot.appendChild(timeLabel);
                
                // Add 7 day columns
                DAYS.forEach((_, dayIndex) =&gt; {
                    const programCell = document.createElement(&#039;div&#039;);
                    programCell.className = &#039;kpfk-program kpfk-offline&#039;;
                    programCell.textContent = &#039;No Data&#039;;
                    
                    // Highlight current time slot
                    if (isCurrentTimeSlot(dayIndex, slot.time)) {
                        programCell.classList.add(&#039;kpfk-current&#039;);
                        programCell.innerHTML = &#039;&lt;div class=&quot;kpfk-live&quot;&gt;LIVE&lt;/div&gt;No Data&#039;;
                    }
                    
                    timeSlot.appendChild(programCell);
                });
                
                content.appendChild(timeSlot);
            });
            
        } catch (e) {
            console.error(&#039;Grid generation failed:&#039;, e);
        }
    }
    
    function tryKPFKConnection() {
        return new Promise((resolve, reject) =&gt; {
            const timeoutId = setTimeout(() =&gt; {
                reject(new Error(errorCodes.TIMEOUT));
            }, 10000);
            
            fetch(KPFK_SCHEDULE_URL, {
                method: &#039;GET&#039;,
                mode: &#039;cors&#039;,
                cache: &#039;no-cache&#039;,
                headers: {
                    &#039;Accept&#039;: &#039;text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8&#039;
                }
            })
            .then(response =&gt; {
                clearTimeout(timeoutId);
                if (!response.ok) {
                    throw new Error(`${errorCodes.HTTP_ERROR} - Status: ${response.status} ${response.statusText}`);
                }
                return response.text();
            })
            .then(html =&gt; {
                if (!html || html.length &lt; 1000) {
                    throw new Error(`${errorCodes.NO_DATA} - Response too short: ${html.length} chars`);
                }
                if (!html.includes(&#039;sched_div&#039;)) {
                    throw new Error(`${errorCodes.NO_DATA} - No schedule container found`);
                }
                resolve(html);
            })
            .catch(error =&gt; {
                clearTimeout(timeoutId);
                if (error.name === &#039;TypeError&#039; &amp;&amp; error.message.includes(&#039;CORS&#039;)) {
                    reject(new Error(`${errorCodes.CORS_BLOCKED} - ${error.message}`));
                } else if (error.name === &#039;TypeError&#039;) {
                    reject(new Error(`${errorCodes.NETWORK_ERROR} - ${error.message}`));
                } else {
                    reject(error);
                }
            });
        });
    }
    
    function setupEventListeners() {
        try {
            // Filter buttons
            const filterButtons = document.querySelectorAll(&#039;.kpfk-filter&#039;);
            filterButtons.forEach(button =&gt; {
                button.addEventListener(&#039;click&#039;, function() {
                    filterButtons.forEach(b =&gt; b.classList.remove(&#039;active&#039;));
                    this.classList.add(&#039;active&#039;);
                    filterByTime(this.getAttribute(&#039;data-time&#039;));
                });
            });
            
            // Search
            const searchInput = document.getElementById(&#039;kpfkSearchInput&#039;);
            if (searchInput) {
                searchInput.addEventListener(&#039;input&#039;, e =&gt; {
                    const term = e.target.value.toLowerCase();
                    const programs = document.querySelectorAll(&#039;.kpfk-program&#039;);
                    programs.forEach(cell =&gt; {
                        const shouldShow = !term || cell.textContent.toLowerCase().includes(term);
                        cell.style.opacity = shouldShow ? &#039;1&#039; : &#039;0.3&#039;;
                    });
                });
            }
        } catch (e) {
            console.warn(&#039;Event listener setup failed:&#039;, e);
        }
    }
    
    function filterByTime(timeRange) {
        try {
            const timeSlots = document.querySelectorAll(&#039;.kpfk-time-slot&#039;);
            timeSlots.forEach(slot =&gt; {
                const timeLabel = slot.querySelector(&#039;.kpfk-time-label&#039;);
                if (!timeLabel) return;
                
                const timeText = timeLabel.textContent;
                const hour = parseInt(timeText.split(&#039;:&#039;)[0]);
                const isPM = timeText.includes(&#039;PM&#039;);
                const hour24 = isPM &amp;&amp; hour !== 12 ? hour + 12 : (!isPM &amp;&amp; hour === 12 ? 0 : hour);
                
                let show = true;
                switch(timeRange) {
                    case &#039;morning&#039;: show = hour24 &gt;= 6 &amp;&amp; hour24 &lt; 12; break;
                    case &#039;afternoon&#039;: show = hour24 &gt;= 12 &amp;&amp; hour24 &lt; 18; break;
                    case &#039;evening&#039;: show = hour24 &gt;= 18 &amp;&amp; hour24 &lt; 24; break;
                    case &#039;overnight&#039;: show = hour24 &gt;= 0 &amp;&amp; hour24 &lt; 6; break;
                }
                
                slot.style.display = show ? &#039;grid&#039; : &#039;none&#039;;
            });
        } catch (e) {
            console.warn(&#039;Time filtering failed:&#039;, e);
        }
    }
    
    function loadData() {
        try {
            showElement(&#039;kpfkLoading&#039;);
            hideElement(&#039;kpfkError&#039;);
            hideElement(&#039;kpfkGrid&#039;);
            hideElement(&#039;kpfkLegend&#039;);
            
            updateStatus(&#039;loading&#039;, &#039;Connecting to KPFK...&#039;);
            
            tryKPFKConnection()
                .then(html =&gt; {
                    // TODO: Parse the HTML and extract schedule data
                    // For now, show we connected but have no parser yet
                    updateStatus(&#039;offline&#039;, &#039;Connected but parser not implemented&#039;);
                    generateEmptyGrid();
                    showElement(&#039;kpfkGrid&#039;);
                    showElement(&#039;kpfkLegend&#039;);
                    hideElement(&#039;kpfkLoading&#039;);
                    
                    const updated = document.getElementById(&#039;kpfkUpdated&#039;);
                    if (updated) {
                        updated.textContent = `Connected to KPFK • HTML parser needed • Last attempt: ${new Date().toLocaleTimeString()}`;
                    }
                })
                .catch(error =&gt; {
                    console.error(&#039;KPFK connection failed:&#039;, error.message);
                    
                    // Determine error type
                    let errorType = &#039;NETWORK_ERROR&#039;;
                    if (error.message.includes(&#039;CORS_BLOCKED&#039;)) errorType = &#039;CORS_BLOCKED&#039;;
                    else if (error.message.includes(&#039;TIMEOUT&#039;)) errorType = &#039;TIMEOUT&#039;;
                    else if (error.message.includes(&#039;HTTP_ERROR&#039;)) errorType = &#039;HTTP_ERROR&#039;;
                    else if (error.message.includes(&#039;NO_DATA&#039;)) errorType = &#039;NO_DATA&#039;;
                    
                    showError(errorType, error.message);
                    
                    // Show empty grid anyway for transparency
                    generateEmptyGrid();
                    showElement(&#039;kpfkGrid&#039;);
                    showElement(&#039;kpfkLegend&#039;);
                });
                
        } catch (e) {
            console.error(&#039;Load data failed:&#039;, e);
            showError(&#039;PARSE_ERROR&#039;, e.message);
        }
    }
    
    function initialize() {
        try {
            updateStatus(&#039;loading&#039;, &#039;Initializing...&#039;);
            setupEventListeners();
            loadData();
            
            // Set up refresh timer
            if (refreshTimer) clearInterval(refreshTimer);
            refreshTimer = setInterval(loadData, REFRESH_INTERVAL);
            
        } catch (e) {
            console.error(&#039;Initialization failed:&#039;, e);
            updateStatus(&#039;error&#039;, &#039;Init failed&#039;);
            showError(&#039;PARSE_ERROR&#039;, `Initialization error: ${e.message}`);
        }
    }
    
    // Public API
    return {
        initialize: initialize,
        loadData: loadData,
        filterByTime: filterByTime,
        getStatus: () =&gt; ({ 
            connectionStatus, 
            lastError, 
            scheduleData: Object.keys(scheduleData).length 
        })
    };
})();

// Safe initialization
(function() {
    function init() {
        try {
            if (typeof KPFKSchedule !== &#039;undefined&#039;) {
                KPFKSchedule.initialize();
            }
        } catch (error) {
            console.error(&#039;KPFK Schedule init error:&#039;, error);
        }
    }
    
    if (document.readyState === &#039;loading&#039;) {
        document.addEventListener(&#039;DOMContentLoaded&#039;, init);
    } else {
        setTimeout(init, 100);
    }
})();
&lt;/script&gt;

&lt;!-- KPFK Donate block (Aiir drop‑in) --&gt;
&lt;style type=&quot;text/css&quot;&gt;:root{ 
