&lt;script&gt;
    (function(){
      const frame = document.getElementById(&#039;zeffyFrame&#039;);
      const fallback = document.getElementById(&#039;fallbackLink&#039;);
      let amount = 10; // default monthly

      function url(){
        const base = &#039;https://www.zeffy.com/en-US/donation-form/kpfk-radio&#039;;
        const params = new URLSearchParams();
        params.set(&#039;amount&#039;, amount);
        params.set(&#039;recurring&#039;,&#039;true&#039;);
        params.set(&#039;frequency&#039;,&#039;monthly&#039;);
        return base + &#039;?&#039; + params.toString();
      }
      
      function update(){
        const u = url();
        frame.src = u;
        if (fallback) fallback.href = u;
        window.gtag?.(&#039;event&#039;,&#039;select_content&#039;,{content_type:&#039;sustainer_amount&#039;, value: amount});
      }
      update();


      // Reveal + count-up
      const prefersReduced = window.matchMedia(&#039;(prefers-reduced-motion: reduce)&#039;).matches;
      const revealIO = new IntersectionObserver((entries)=&gt;{
        entries.forEach(entry=&gt;{
          if(!entry.isIntersecting) return;
          entry.target.classList.add(&#039;show&#039;);
          entry.target.querySelectorAll(&#039;.count&#039;).forEach(el=&gt;{
            const to = parseInt(el.dataset.count,10) || 0;
            if(prefersReduced){ el.textContent = to; return; }
            let t0 = performance.now(), dur = 800;
            const step = (t)=&gt;{
              const p = Math.min(1,(t - t0)/dur);
              el.textContent = Math.floor(p*to);
              if(p&lt;1) requestAnimationFrame(step);
            };
            requestAnimationFrame(step);
          });
          revealIO.unobserve(entry.target);
        });
      }, {threshold: .15});
      document.querySelectorAll(&#039;.reveal&#039;).forEach(el=&gt;revealIO.observe(el));
    })();
  &lt;/script&gt;&lt;script src=&quot;https://zeffy-scripts.s3.ca-central-1.amazonaws.com/embed-form-script.min.js&quot;&gt;&lt;/script&gt;&lt;script&gt;
    (function(){
      const isKpfk = (u)=&gt;{ try{ return new URL(u, location.href).hostname.endsWith(&#039;kpfk.org&#039;); }catch(e){ return false; } };
      document.querySelectorAll(&#039;a[href]&#039;).forEach(a=&gt;{
        const href = a.getAttribute(&#039;href&#039;);
        if(!href || href.startsWith(&#039;#&#039;) || a.target) return;
        if(!isKpfk(href)){
          a.target = &#039;_blank&#039;;
          a.rel = &#039;noopener noreferrer&#039;;
        }
      });
    })();
  &lt;/script&gt;

