&lt;h2 id=&quot;faq-title&quot; style=&quot;text-align:center;margin-bottom:24px&quot;&gt;Questions?&lt;/h2&gt;

&lt;details&gt;&lt;summary&gt;Is my donation tax-deductible?&lt;/summary&gt;

&lt;p class=&quot;sub&quot;&gt;Yes. Pacifica Foundation EIN 94-1347046. You&amp;#39;ll get an emailed receipt for your records within 24 hours.&lt;/p&gt;
&lt;/details&gt;

&lt;details&gt;&lt;summary&gt;How do I change or cancel my monthly pledge?&lt;/summary&gt;

&lt;p class=&quot;sub&quot;&gt;Please contact us directly for assistance with changing or cancelling your monthly pledge. We&amp;#39;ll help you adjust or cancel quickly, no questions asked.&lt;/p&gt;
&lt;/details&gt;

&lt;details&gt;&lt;summary&gt;Do I get voting rights?&lt;/summary&gt;

&lt;p class=&quot;sub&quot;&gt;Yes! $25/year+ (or $5/mo+) gives you Pacifica voting rights. Ballots and candidate info are emailed during election cycles, usually annually.&lt;/p&gt;
&lt;/details&gt;

&lt;details&gt;&lt;summary&gt;Where exactly does my money go?&lt;/summary&gt;

&lt;p class=&quot;sub&quot;&gt;Three main areas: &lt;strong&gt;Operations&lt;/strong&gt; (keeping our 110,000-watt signal broadcasting 24/7), &lt;strong&gt;Programming&lt;/strong&gt; (paying producers, covering news, training new voices), and &lt;strong&gt;Community Access&lt;/strong&gt; (youth programs, equipment, emerging producers getting on-air).&lt;/p&gt;
&lt;/details&gt;

&lt;details&gt;&lt;summary&gt;Can I give via stock, vehicle, or estate?&lt;/summary&gt;

&lt;p class=&quot;sub&quot;&gt;Absolutely. See &amp;quot;Other Ways to Support Independence&amp;quot; above for all the options and contact info. We work with donors on creative giving all the time.&lt;/p&gt;
&lt;/details&gt;
&lt;/section&gt;
&lt;script&gt;
    (function(){
      let amount = 10; // default monthly (kept for potential future use or analytics if needed)

      // Reveal + count-up (KEPT AS IS)
      const prefersReduced = window.matchMedia(&#039;(prefers-reduced-motion: reduce)&#039;).matches;
      const revealIO = new IntersectionObserver((entries)=&gt;{
        entries.forEach(entry=&gt;{
          if(!entry.isIntersecting) return;
          entry.target.classList.add(&#039;show&#039;);
          entry.target.querySelectorAll(&#039;.count&#039;).forEach(el=&gt;{
            const to = parseInt(el.dataset.count,10) || 0;
            if(prefersReduced){ el.textContent = to; return; }
            let t0 = performance.now(), dur = 800;
            const step = (t)=&gt;{
              const p = Math.min(1,(t - t0)/dur);
              el.textContent = Math.floor(p*to);
              if(p&lt;1) requestAnimationFrame(step);
            };
            requestAnimationFrame(step);
          });
          revealIO.unobserve(entry.target);
        });
      }, {threshold: .15});
      document.querySelectorAll(&#039;.reveal&#039;).forEach(el=&gt;revealIO.observe(el));
    })();
  &lt;/script&gt;&lt;script&gt;
